pub fn get(&mut self, key: &K) -> Option<&V> {
    self.map.get(key).map(|(v, _)| v)
}

pub fn get_or_insert<F>(&mut self, key: K, f: F) -> &V
where
    F: FnOnce() -> V,
    K: Clone,
{
    if self.map.contains_key(&key) {
        return self.get(&key).unwrap();
    }
    let value = f();
    self.put(key.clone(), value);
    self.get(&key).unwrap()
}

